from typing import Callable, List, Optional

def numb(n: int) -> int:
    if n == 0:
        return 1
    return numb(n - 1) * n

def rslt(n: int) -> int:
    if n == 0:
        return 1
    return rslt(n - 1) * n

def fact(n: int) -> int:
    if n == 0:
        return 1
    return fact(n - 1) * n
```

